"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[23],{5213:e=>{e.exports=JSON.parse('{"functions":[{"name":"exportAs","desc":"Registers this UniPlugin under `alias` in the shared exports table, making\\nit discoverable by other plugins calling `withImports`. Fires the global\\nExportOpened event so any waiting `withImports` listeners are unblocked.\\n\\nThe returned listener\'s `close` removes the export and can be called\\nmanually; it is also called automatically when the plugin unloads or is\\ndestroyed.\\n\\n\\n**Example Usage:**\\n```lua\\nlocal UniPlugin = require(path.to.module)(plugin)\\n\\nUniPlugin:setApi(\\"output\\", {\\n\\tprint = print,\\n\\twarn = warn,\\n\\terror = error\\n})\\nUniPlugin:setApi(\\"requireInMyContext\\", {\\n\\texecute = function(module) return require(module) end\\n})\\nUniPlugin:exportAs(\\"athar-adv/MyPlugin\\")","params":[{"name":"self","desc":"","lua_type":"UniPlugin"},{"name":"alias","desc":"The name to register this plugin under","lua_type":"string"}],"returns":[{"desc":"A connection that can be closed to unregister the export","lua_type":"UniPluginConnection"}],"function_type":"static","errors":[{"lua_type":"\\"UniPlugin \'{self.plugin.Name}\' is closed, cannot call UniPlugin:exportAs(...)\\"","desc":"Occurs if UniPlugin.isClosed is true."}],"source":{"line":119,"path":"src/init.luau"}},{"name":"withImports","desc":"Waits for all plugins in `aliases` to be exported, then calls `handler`\\nwith two arguments:\\n- `plugins()` \u2014 returns all resolved UniPlugins in the same order as `aliases` via multiple returns.\\n- `bindOnImportClosed(fn)` \u2014 registers a single callback (overwriting any previous one) that fires whenever this import group is torn down, whether because one of the imported plugins closed naturally or because the returned listener was closed manually.\\n\\nThe handler re-runs automatically each time all aliases become available\\nagain after a close. Duplicate aliases are silently deduplicated. Passing\\nan empty `aliases` table is a no-op and returns an inert connection.\\n\\nClose the returned connection to stop listening entirely and tear down the\\ncurrent import group.\\n\\n\\n**Example Usage:**\\n```lua\\nlocal UniPlugin = require(path.to.module)(plugin)\\n\\nUniPlugin:withImports({\\"athar-adv/Jexplorer\\", \\"athar-adv/SimpleComplete\\"}, function(plugins, onImportClosed)\\n\\tlocal jexplorer, simpleComplete = plugins()\\n\\n\\tlocal items = {}\\n\\tdo\\n\\t\\tlocal manager = jexplorer:getApi(\\"manager\\")\\n\\t\\tmanager.setSetting(\\"VirtualScrollFrameBuffer\\", 20)\\n\\t\\t\\n\\t\\ttable.insert(items, manager.ExplorerFrame.ClassIconStyleRuleCreated:Connect(function(rule)\\n\\t\\t\\trule:SetProperty(\\"Image\\", \\"rbxassetid://1234\\")\\n\\t\\tend))\\n\\tend\\n\\tdo\\n\\t\\tlocal selectionImports = simpleComplete:getApi(\\"selectionImports\\")\\n\\n\\t\\tselectionImports.triggerAtCurrentPosition()\\n\\tend\\n\\tonImportClosed(function()\\n\\t\\tfor _, v in items do\\n\\t\\t\\tv:Disconnect()\\n\\t\\tend\\n\\tend)\\nend)","params":[{"name":"self","desc":"","lua_type":"UniPlugin"},{"name":"aliases","desc":"List of plugin export aliases to wait for","lua_type":"{string}"},{"name":"handler","desc":"Called once all aliases are available; re-runs if the group is torn down and re-established","lua_type":"(plugins: () -> ...UniPlugin, bindOnImportClosed: (fn: () -> ()) -> ()) -> ()"}],"returns":[{"desc":"A connection that can be closed to stop tracking imports","lua_type":"UniPluginConnection"}],"function_type":"static","errors":[{"lua_type":"\\"UniPlugin \'{self.plugin.Name}\' is closed, cannot call UniPlugin:withImports(...)\\"","desc":"Occurs if UniPlugin.isClosed is true."}],"source":{"line":191,"path":"src/init.luau"}},{"name":"onClose","desc":"Registers `fn` to be called when this plugin is torn down (i.e. when the\\nplugin unloads or is destroyed). Multiple listeners can be registered and\\nall will fire on close.\\n\\nThe returned listener\'s `close` unregisters `fn` and can be used to cancel\\nthe subscription before the plugin closes.\\n\\n\\n**Example Usage:**\\n```lua\\nlocal UniPlugin = require(path.to.module)(plugin)\\n\\nUniPlugin:onClose(function()\\n\\tprint(\\"Whyd you close my plugin :(\\")\\nend)","params":[{"name":"self","desc":"","lua_type":"UniPlugin"},{"name":"fn","desc":"Callback to invoke on plugin teardown","lua_type":"() -> ()"}],"returns":[{"desc":"A connection that can be closed to cancel the subscription","lua_type":"UniPluginConnection"}],"function_type":"static","errors":[{"lua_type":"\\"UniPlugin \'{self.plugin.Name}\' is closed, cannot call UniPlugin:onClose(...)\\"","desc":"Occurs if UniPlugin.isClosed is true."}],"source":{"line":330,"path":"src/init.luau"}},{"name":"setApi","desc":"Stores `api` under `alias` (defaults to `\\"main\\"`) on this UniPlugin.\\nRetrieve it from another plugin via `getApi`.\\n\\n\\n**Example Usage:**\\n```lua\\nlocal UniPlugin = require(path.to.module)(plugin)\\n\\nUniPlugin:setApi(\\"output\\", {\\n\\tprint = print,\\n\\twarn = warn,\\n\\terror = error\\n})\\nUniPlugin:setApi(\\"requireInMyContext\\", {\\n\\texecute = function(module) return require(module) end\\n})\\nUniPlugin:exportAs(\\"athar-adv/MyPlugin\\")","params":[{"name":"self","desc":"","lua_type":"UniPlugin"},{"name":"alias","desc":"The alias to store the API under. Defaults to `\\"main\\"`","lua_type":"string?"},{"name":"api","desc":"The API table to store","lua_type":"Api"}],"returns":[],"function_type":"static","errors":[{"lua_type":"\\"UniPlugin \'{self.plugin.Name}\' is closed, cannot call UniPlugin:setApi(...)\\"","desc":"Occurs if UniPlugin.isClosed is true."}],"source":{"line":370,"path":"src/init.luau"}},{"name":"getApi","desc":"Returns the Api stored under `alias` (defaults to `\\"main\\"`).\\nErrors if no Api has been set for that alias.\\n\\n\\n**Example Usage:**\\n```lua\\nlocal UniPlugin = require(path.to.module)(plugin)\\n\\nUniPlugin:withImports({\\"athar-adv/Jexplorer\\", \\"athar-adv/SimpleComplete\\"}, function(plugins, onImportClosed)\\n\\tlocal jexplorer, simpleComplete = plugins()\\n\\n\\tlocal items = {}\\n\\tdo\\n\\t\\tlocal manager = jexplorer:getApi(\\"manager\\")\\n\\t\\tprint(manager.executeJqlQuery(\\"#?player\\"))\\n\\n\\t\\tlocal dependencies = jexplorer:getApi(\\"dependencies\\")\\n\\t\\tprint(dependencies.GitApi)\\n\\tend\\n\\tdo\\n\\t\\tlocal editor = simpleComplete:getApi(\\"editor\\")\\n\\t\\tprint(editor.getOpenDocValue().currentImportedModules)\\n\\tend\\nend)","params":[{"name":"self","desc":"","lua_type":"UniPlugin"},{"name":"alias","desc":"The alias to look up. Defaults to `\\"main\\"`","lua_type":"string?"}],"returns":[{"desc":"The stored API table","lua_type":"Api"}],"function_type":"static","errors":[{"lua_type":"\\"UniPlugin \'{self.plugin.Name}\' is closed, cannot call UniPlugin:getApi(...)\\"","desc":"Occurs if UniPlugin.isClosed is true."}],"source":{"line":407,"path":"src/init.luau"}},{"name":"close","desc":"Closes this UniPlugin. Cleans up any connections, fires `onClose` handlers,\\nand makes all methods error on subsequent calls.\\n\\n\\n**Example Usage:**\\n```lua\\nlocal UniPlugin = require(path.to.module)(plugin)\\n\\n--[[snip!]]\\n\\nclosePluginButton.Activated:Connect(function()\\n\\tUniPlugin:close()\\nend)\\n\\nUniPlugin:onClose(function()\\n\\tfor _, v in connections do v:Disconnect() end\\nend)","params":[{"name":"self","desc":"","lua_type":"UniPlugin"}],"returns":[],"function_type":"static","source":{"line":434,"path":"src/init.luau"}},{"name":"openUniPlugin","desc":"Returns the UniPlugin instance for the given `plugin`, creating it if one\\ndoesn\'t already exist. Only one UniPlugin is ever created per Plugin\\ninstance for the lifetime of the studio session.\\n\\nAutomatically connects to `plugin.Unloading` and `plugin.Destroying` to\\nfire all `onClose` listeners and close all active `withImports` and\\n`exportAs` listeners when the plugin is torn down.","params":[{"name":"plugin","desc":"The Roblox Plugin instance to wrap","lua_type":"Plugin"}],"returns":[{"desc":"","lua_type":"UniPlugin"}],"function_type":"static","source":{"line":466,"path":"src/init.luau"}}],"properties":[{"name":"plugin","desc":"The Plugin this UniPlugin is associated with.","lua_type":"Plugin","source":{"line":41,"path":"src/init.luau"}},{"name":"apis","desc":"All registered public apis.","lua_type":"{[string]: Api}","source":{"line":46,"path":"src/init.luau"}},{"name":"isClosed","desc":"If `UniPlugin:close()` has been called. If this is true, calling any method will throw an error.","lua_type":"boolean","source":{"line":51,"path":"src/init.luau"}}],"types":[{"name":"Api","desc":"A publicly exported interface for the UniPlugin.","lua_type":"{[string]: any}","source":{"line":15,"path":"src/init.luau"}}],"name":"UniPlugin","desc":"Wraps a Roblox `Plugin` instance to provide a shared\\nexport/import system between plugins.","source":{"line":36,"path":"src/init.luau"}}')}}]);